import React from 'react';

const platformsData = [
  {
    title: "E-commerce",
    icon: "bi bi-cart",
    description: "Developed and customized e-commerce solutions using Shopware, optimizing performance, integrating payment gateways, and enhancing user experience."
  },
  {
    title: "ERP Systems",
    icon: "bi bi-building",
    description: "Built and implemented ERP systems for manufacturing companies, streamlining operations, automating workflows, and improving resource management."
  },
  {
    title: "CRM Portals",
    icon: "bi bi-person-check",
    description: "Developed monitoring portals for customer relationship management, enabling efficient tracking, reporting, and data-driven decision-making."
  },
  {
    title: "CMS",
    icon: "bi bi-file-text",
    description: "Designed and implemented a CMS for education management systems, allowing efficient content organization and user management."
  },
  {
    title: "Payment Gateway",
    icon: "bi bi-credit-card",
    description: "Integrated secure third-party payment systems ensuring seamless checkout experiences and financial compliance."
  },
  {
    title: "API Integration",
    icon: "bi bi-link",
    description: "Integrated various service APIs enabling seamless data exchange, enhanced functionality, and business automation."
  }
];

const Platforms = () => {
  return (
    <section id="platforms" className="platforms section">
      <div className="container section-title" data-aos="fade-up">
        <h2 className="text-gradient">Platforms & Specializations</h2>
        <p>Experienced in developing scalable solutions across various ecosystem tailored to business needs.</p>
      </div>
      <div className="container">
        <div className="row g-4">
          {platformsData.map((platform, idx) => (
            <div key={idx} className="col-lg-4 col-md-6" data-aos="zoom-in" data-aos-delay={idx * 100}>
              <div className="platform-card glass-effect h-100 p-5 text-center position-relative">
                <div className="icon mb-4">
                  <i className={`${platform.icon} text-gradient fs-1`}></i>
                </div>
                <h3 className="mb-3">{platform.title}</h3>
                <p className="text-muted">{platform.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Platforms;
